import { Logger } from '@byted-service/logger';
import { TraceId } from './tracerId';
import * as ktypes from '../types';
import * as kspan from '../span';
import { ClientOptions } from '@byted-nodex/metrics';
export type StartSpanOptions = Partial<Omit<ktypes.StartSpanOptions, 'postTraceCtxFromChild'>> & {
    /**
     * 父 span，不传 parentSpan 将会新建一个 transaction，新建 span 作为 root span。
     */
    parentSpan?: kspan.Span;
    /**
     * 调用链路 logid，不传入此 logid 将不会采样，tracerID 由 logid 计算得到。
     */
    logId?: string;
};
export interface TracerOptions {
    /**
     * spanLogger 是一个 level 为 trace 的 logger 实例，应该有框架传入(gulu、rpc)
     * 否则默认值为 NoopLogger 不会输出任何 log
     */
    spanLogger?: Logger;
    /**
     * serverSpanLogger 是一个 level 为 trace 的 logger 实例，应该有框架传入(gulu、rpc)
     * 否则默认值为 NoopLogger 不会输出任何 log
     */
    serverSpanLogger?: Logger;
    /**
     * clientSpanLogger 是一个 level 为 trace 的 logger 实例，应该有框架传入(gulu、rpc)
     * 否则默认值为 NoopLogger 不会输出任何 log
     */
    clientSpanLogger?: Logger;
    /**
     * env env.Environment
     * 环境
     */
    env?: {
        /**
         * service name , like psm
         * 服务的名称,例如 psm
         */
        serviceName?: string;
        /**
         * dc of service
         * 服务所在的机房
         */
        dc?: string;
        /**
         * cluster
         * 集群名字
         */
        cluster?: string;
        /**
         * Canary,Single DC,All
         * 小流量,单机房,全流量
         */
        stage?: string;
        /**
         * ipv4 address of service
         * 服务的ipv4地址
         */
        ipv4?: string;
        /**
         * ipv6 address of service
         * 服务的ipv6地址
         */
        ipv6?: string;
        /**
         * podName
         * podName 实例名字
         */
        podName?: string;
        /**
         * 服务的语言
         */
        env?: string;
        /**
         * Framework defines the service framework used in sdk.
         * Framework 定义了 sdk 中使用的服务框架。
         */
        framework?: string;
    };
    /**
     * SDK 内部使用的 logger 实例
     */
    logger?: Logger;
    /**
     * Disable dynamic configuration, use local static configs only
     * 禁止动态获取配置，使用本地静态配置
     */
    disableDynamicConfig?: boolean;
    /**
     * Disable metrics
     * 禁止 metrics 打点
     */
    disableMetrics?: boolean;
    metricClientOptions?: ClientOptions;
    /**
     * Enable Send Recv bytes metrics
     * 允许发送接送到的数据长度的 metrics 打点
     */
    enableSendRecvBytesMetrics?: boolean;
    /**
     * Enable collect tracer status and get status by tracer.getStatus()
     * 允许通过 getStatus 方法收集 sdk 的状态
     */
    enableCollectTracerStatus?: boolean;
    /**
     * Generate traceID's high part
     * 生成 trace id 的高位部分
     */
    highTraceIdGenerator?: () => number;
    /**
     * GenTraceId by logId for postTrace, make postTrace no status
     * posttrace 时，如果没有 trace id，则根据 logid 通过这个函数生成 trace id
     */
    postTraceIDGenerator?: (logId: string) => TraceId;
    /**
     *  Generate seed for sampler
     * 为采样器生成采样概率种子
     */
    samplingSeedGenerator?: () => bigint;
    /**
     * Whether disable report remote address in metrics if span has err when span finish
     * 当 span 发生错误时，禁止打 metrics 的时候上报远端地址
     */
    disableReportRemoteAddrWhenErr?: boolean;
    /**
     * 禁用上报 span
     */
    disableReportSpan?: boolean;
}
export interface TracerStatus {
    tracerConfigs: {
        globalTracerConfig: string;
        breakerConfig: string;
        samplerConfig: string;
    };
    reportingBps: number;
    reportingQps: number;
    degradeQps: number;
}
